-- Add language support to settings table
ALTER TABLE settings ADD COLUMN language VARCHAR(5) DEFAULT 'en' AFTER category;

-- Drop the old unique constraint on setting_key
ALTER TABLE settings DROP INDEX setting_key;

-- Add new unique constraint on (setting_key, language)
ALTER TABLE settings ADD UNIQUE KEY unique_setting_key_language (setting_key, language);

-- Update existing settings to English
UPDATE settings SET language = 'en' WHERE language IS NULL OR language = '';

